SELECT DISTINCT p.supplier_name AS value
FROM new_purchase_info p
INNER JOIN new_product_work_20260510 pr ON pr.id = p.product_id
INNER JOIN new_category c ON c.id = pr.category_id
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
AND c.small_category = #{smallCategory}
AND p.supplier_name IS NOT NULL
AND TRIM(p.supplier_name) != ''
ORDER BY p.supplier_name

SELECT DISTINCT pr.product_name AS value
FROM new_product_work_20260510 pr
INNER JOIN new_category c ON c.id = pr.category_id
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
AND c.small_category = #{smallCategory}
AND pr.active = 1
ORDER BY pr.product_name

SELECT c.id
FROM new_category c
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
AND c.small_category = #{smallCategory}
LIMIT 1

SELECT COUNT(*)
FROM new_purchase_info
WHERE id = #{id}

SELECT COUNT(*)
FROM new_purchase_info
WHERE purchase_date = #{purchaseDate}
AND total_cost = #{totalCost}


        AND purchase_time = #{purchaseTime}


        AND purchase_time IS NULL

SELECT COUNT(*)
FROM new_purchase_info
WHERE id != #{id}
AND purchase_date = #{purchaseDate}
AND total_cost = #{totalCost}


        AND purchase_time = #{purchaseTime}


        AND purchase_time IS NULL

